import { useState, useEffect, useRef } from "react";
import { Link } from "react-router-dom";
import {
  Menu,
  X,
  ChevronDown,
  User,
  LogOut,
  Settings,
} from "lucide-react";

const navLinks = [
  { name: "Home", href: "#home" },
  { name: "Destinations", href: "#destinations" },
  { name: "Why Us", href: "#features" },
  { name: "How It Works", href: "#how-it-works" },
  { name: "Testimonials", href: "#testimonials" },
];

export const Header = ({ user, onLogoutClick }) => {
  const [scrolled, setScrolled] = useState(false);
  const [mobileMenuOpen, setMobileMenuOpen] = useState(false);
  const [dropdownOpen, setDropdownOpen] = useState(false);
  const dropdownRef = useRef(null);

  useEffect(() => {
    const handleScroll = () => setScrolled(window.scrollY > 60);
    window.addEventListener("scroll", handleScroll);
    return () => window.removeEventListener("scroll", handleScroll);
  }, []);

  useEffect(() => {
    const handleClickOutside = (e) => {
      if (dropdownRef.current && !dropdownRef.current.contains(e.target)) {
        setDropdownOpen(false);
      }
    };
    document.addEventListener("mousedown", handleClickOutside);
    return () => document.removeEventListener("mousedown", handleClickOutside);
  }, []);

  const scrollToSection = (href) => {
    const el = document.querySelector(href);
    if (el) el.scrollIntoView({ behavior: "smooth" });
    setMobileMenuOpen(false);
  };

  return (
    <header
      className={`fixed top-0 left-0 right-0 z-50 transition-all duration-500 ${
        scrolled
          ? "bg-brand-green shadow-xl shadow-black/10 py-0"
          : "bg-gradient-to-b from-black/40 to-transparent py-1"
      }`}
    >
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex items-center justify-between h-[72px]">
          {/* Logo */}
          <Link to="/" className="flex items-center gap-3 group shrink-0">
            <img
              src="/logo-offtrail.png"
              alt="OffTrail Nepal"
              className={`rounded-full object-cover transition-all duration-300 ${
                scrolled
                  ? "h-11 w-11 ring-2 ring-white/20"
                  : "h-12 w-12 ring-2 ring-white/30"
              } group-hover:ring-white/60`}
            />
            <div className="flex items-baseline">
              <span className="text-xl font-extrabold text-white tracking-tight">
                OffTrail
              </span>
              <span className="text-xl font-extrabold text-brand-orange ml-1">
                Nepal
              </span>
            </div>
          </Link>

          {/* Desktop Nav */}
          <nav className="hidden lg:flex items-center gap-1">
            {navLinks.map((link) => (
              <button
                key={link.name}
                onClick={() => scrollToSection(link.href)}
                className="px-4 py-2 text-[13px] font-semibold uppercase tracking-wider text-white/80 hover:text-white hover:bg-white/10 rounded-lg transition-all duration-300"
              >
                {link.name}
              </button>
            ))}
          </nav>

          {/* Right Side */}
          <div className="flex items-center gap-3">
            {user ? (
              /* Logged-in User Dropdown */
              <div className="relative" ref={dropdownRef}>
                <button
                  onClick={() => setDropdownOpen(!dropdownOpen)}
                  className="flex items-center gap-2.5 px-3 py-2 rounded-xl hover:bg-white/10 transition group"
                >
                  <div className="h-9 w-9 rounded-full bg-gradient-to-br from-brand-orange to-brand-orange-soft flex items-center justify-center text-white font-bold text-sm ring-2 ring-white/30">
                    {user.full_name?.charAt(0).toUpperCase() || "U"}
                  </div>
                  <div className="hidden md:block text-left">
                    <p className="text-sm font-semibold text-white leading-tight">
                      {user.full_name || "User"}
                    </p>
                    <p className="text-[11px] text-white/50 capitalize">
                      {user.user_type}
                    </p>
                  </div>
                  <ChevronDown
                    className={`h-4 w-4 text-white/50 transition-transform duration-300 ${
                      dropdownOpen ? "rotate-180" : ""
                    }`}
                  />
                </button>

                {dropdownOpen && (
                  <div className="absolute right-0 mt-3 w-64 bg-white rounded-2xl shadow-2xl border border-gray-100 py-2 animate-slide-down">
                    <div className="px-4 py-3 border-b border-gray-100">
                      <p className="text-sm font-bold text-gray-900">
                        {user.full_name}
                      </p>
                      <p className="text-xs text-gray-500 mt-0.5">
                        {user.email}
                      </p>
                      <span className="inline-block mt-2 px-3 py-1 bg-brand-green/10 text-brand-green text-xs font-semibold rounded-full capitalize">
                        {user.user_type}
                      </span>
                    </div>
                    <div className="py-1">
                      <button className="w-full text-left px-4 py-2.5 text-sm text-gray-700 hover:bg-gray-50 flex items-center gap-3 transition">
                        <User className="h-4 w-4 text-gray-400" />
                        My Profile
                      </button>
                      <button className="w-full text-left px-4 py-2.5 text-sm text-gray-700 hover:bg-gray-50 flex items-center gap-3 transition">
                        <Settings className="h-4 w-4 text-gray-400" />
                        Settings
                      </button>
                    </div>
                    <div className="border-t border-gray-100 pt-1">
                      <button
                        onClick={() => {
                          onLogoutClick();
                          setDropdownOpen(false);
                        }}
                        className="w-full text-left px-4 py-2.5 text-sm text-red-600 hover:bg-red-50 flex items-center gap-3 transition"
                      >
                        <LogOut className="h-4 w-4" />
                        Logout
                      </button>
                    </div>
                  </div>
                )}
              </div>
            ) : (
              /* Guest Auth Buttons */
              <div className="hidden sm:flex items-center gap-3">
                <Link
                  to="/login"
                  className="px-5 py-2.5 text-sm font-semibold text-white border border-white/25 hover:bg-white/10 rounded-lg transition-all duration-300"
                >
                  Log in
                </Link>
                <Link
                  to="/register"
                  className="px-5 py-2.5 text-sm font-bold bg-brand-orange hover:bg-brand-orange-muted text-white rounded-lg transition-all duration-300 shadow-lg shadow-brand-orange/30"
                >
                  Sign Up Free
                </Link>
              </div>
            )}

            {/* Mobile Menu Toggle */}
            <button
              onClick={() => setMobileMenuOpen(!mobileMenuOpen)}
              className="lg:hidden p-2 rounded-lg text-white hover:bg-white/10 transition"
              aria-label="Toggle menu"
            >
              {mobileMenuOpen ? (
                <X className="h-6 w-6" />
              ) : (
                <Menu className="h-6 w-6" />
              )}
            </button>
          </div>
        </div>
      </div>

      {/* Mobile Menu */}
      {mobileMenuOpen && (
        <div className="lg:hidden bg-brand-green-dark/98 backdrop-blur-xl border-t border-white/10 animate-slide-down">
          <div className="px-4 py-5 space-y-1 max-w-md mx-auto">
            {navLinks.map((link) => (
              <button
                key={link.name}
                onClick={() => scrollToSection(link.href)}
                className="block w-full text-left px-4 py-3.5 text-white/80 hover:text-white hover:bg-white/10 rounded-xl transition font-medium text-[15px]"
              >
                {link.name}
              </button>
            ))}
            {!user && (
              <div className="pt-5 mt-3 border-t border-white/10 space-y-3">
                <Link
                  to="/login"
                  onClick={() => setMobileMenuOpen(false)}
                  className="block w-full text-center px-4 py-3.5 text-white border border-white/20 rounded-xl hover:bg-white/10 transition font-semibold"
                >
                  Log in
                </Link>
                <Link
                  to="/register"
                  onClick={() => setMobileMenuOpen(false)}
                  className="block w-full text-center px-4 py-3.5 bg-brand-orange text-white rounded-xl hover:bg-brand-orange-muted transition font-bold shadow-lg"
                >
                  Sign Up Free
                </Link>
              </div>
            )}
          </div>
        </div>
      )}
    </header>
  );
};
